double noise(double x, double y, double z, double w) {
  final double F4 = (Math.sqrt(5.0)-1.0)/4.0;
  final double G4 = (5.0-Math.sqrt(5.0))/20.0;
  double n0, n1, n2, n3, n4; // Noise contributions from the five corners
  // Skew the (x,y,z,w) space to determine which cell of 24 simplices we're in
  double s = (x + y + z + w) * F4; // Factor for 4D skewing
  int i = fastfloor(x + s);
  int j = fastfloor(y + s);
  int k = fastfloor(z + s);
  int l = fastfloor(w + s);
  double t = (i + j + k + l) * G4; // Factor for 4D unskewing
  double X0 = i - t; // Unskew the cell origin back to (x,y,z,w) coords
  double y0 = j - t; // Unskew the cell origin back to (x,y,z,w) coords
  double z0 = k - t; // Unskew the cell origin back to (x,y,z,w) coords
  double w0 = l - t; // Unskew the cell origin back to (x,y,z,w) coords
  int ii = i & 255; // Wrap the integer coordinates at 256
  int jj = j & 255; // Wrap the integer coordinates at 256
  int kk = k & 255; // Wrap the integer coordinates at 256
  int ll = l & 255; // Wrap the integer coordinates at 256
  double n0 = dot(grad4[perm(ii, jj, kk, ll)], x0, y0, z0, w0);
  double n1 = dot(grad4[perm(ii + i1, jj + j1, kk + k1, ll + l1)], x1, y1, z1, w1);
  double n2 = dot(grad4[perm(ii + i2, jj + j2, kk + k2, ll + l2)], x2, y2, z2, w2);
  double n3 = dot(grad4[perm(ii + i3, jj + j3, kk + k3, ll + l3)], x3, y3, z3, w3);
  double n4 = dot(grad4[perm(ii + 1, jj + 1, kk + 1, ll + 1)], x4, y4, z4, w4);
  return 27.0 * (n0 + n1 + n2 + n3 + n4);
}

