    //Helper method to print out a matrix in a readable format
    public static void printMatrix(Matrix4f m){
        for(int i = 0; i < 4; i++){
            System.out.print(i + ": ");
            for(int j = 0; j < 4; j++)
                System.out.print(m.get(j, i) + " ");
            System.out.println("");
        }
    }
}

